);
const UnhandledStatusErrorPage = dynamic(
  () => import('../errorPages/UnhandledStatusErrorPage'),
);

type Props = {
  showSurfaceFoundSpinner: boolean;
  renderOnPollComplete?: (interest: Cloud$Interest) => ReactElement;
  pollUntilFunction: (interest: Cloud$Interest) => boolean;
  isLoadingTextHidden?: boolean;
  /**
   * Because we want to reuse this interest polling for a new Tetris page,
   * and we will lose the interest details if the user would refresh this page
   */
  waitWithRenderForAtLeast?: number;
};

const InterestPollWrapper = ({
  waitWithRenderForAtLeast,
  renderOnPollComplete,
  showSurfaceFoundSpinner,
  isLoadingTextHidden,
  pollUntilFunction,
}: Props) => {
  const router = useRouter();
  const { query } = router;
  const { formatMessage } = useIntl();
  const id = getFirstFromArray(query.id);

  const [shouldWaitWithRender, setShouldWaitWithRender] = useState(
    !!waitWithRenderForAtLeast,
  );

  useEffect(() => {
    if (!waitWithRenderForAtLeast) {
      return undefined;
    }
    const timer = setTimeout(() => {
      setShouldWaitWithRender(false);
    }, waitWithRenderForAtLeast);
    return () => clearTimeout(timer);
  }, [shouldWaitWithRender, waitWithRenderForAtLeast]);

  const { interest, fetchInterestError, isPolling } = useInterest(id, {
    pollUntilFunction,
  });

  if (interest?.status === interestStatus.AWAITING_LAUNCH) {
    return (
      <InterestCapturePage
        isInterestCaptured={!!interest.email}
        interestId={interest.id}
      />
    );
  }

  if (interest?.status === interestStatus.OUTSIDE_SERVICE_AREA) {
    return (
      <UnhandledStatusErrorPage
        heading={<T {...messages.outsideServiceArea} />}
        body={<T {...messages.outsideServiceAreaDescription} />}
      />
    );
  }

  if (interest?.status === interestStatus.SPECIAL_CASE) {
    return (
      <UnhandledStatusErrorPage
        heading={<T {...messages.tooSmallInstallation} />}
        body={
          <T
            {...messages.tooSmallInstallationDescription}
            values={{
              email: <OtovoEmailLink />,
            }}
          />
        }
      />
    );
  }

  if (interest?.status === interestStatus.CALC_FAILED) {
    return <InterestErrorPage />;
  }

  if (fetchInterestError) {
    return (
      <div data-testid="interest-404-page">
        <ErrorStatusPage status={404} />
      </div>
    );
  }

  if (interest && !isPolling && !shouldWaitWithRender) {
    return renderOnPollComplete(interest);
  }

  return (
    <Box>
      {showSurfaceFoundSpinner ? (
        <SurfaceFoundSpinner
          messages={
            !isLoadingTextHidden
              ? [
                  formatMessage(messages.findingAvailableInstallers),
                  formatMessage(messages.checkingSavings),
                  formatMessage(messages.preparingPriceEstimate),
                ]
              : []
          }
        />
      ) : (
        <NoSurfaceSpinner
          changeInterval={5000}
          errorMessage={`${formatMessage(messages.timeoutErrorMessage)} ☀️`}
          messages={
            !isLoadingTextHidden
              ? [
                  formatMessage(messages.searchingForYourAddress),
                  formatMessage(messages.solarPotentialInYourArea),
                  formatMessage(messages.findingAvailableInstallers),
                ]
              : []
          }
          onTimeout={() => {
            logToSentry('Timed out while waiting for a calculation');
          }}
        />
      )}
    </Box>
  );
};

export default InterestPollWrapper;
