import { logCalculationShown } from '@otovo/shared/lib/analytics/analytics';
import {
  Cloud$MainHardwareType,
  Cloud$PackageSize,
  Cloud$ProductName,
  Cloud$PurchaseModelCode,
} from '@otovo/shared/types/cloudEnums';
import { Surface$MapPolygon } from '@otovo/shared/types/surfaceTypes';
import dynamic from 'next/dynamic';
import { Dispatch, useEffect } from 'react';
import { InterestActionTypes } from '../../stores/Interest/reducer';
import { InterestStore } from '../../stores/Interest/type';
import CalcPage from './CalcPage';
import { useShoppingCart } from './useShoppingCart';
import useUpdateSurfaces from './useUpdateSurfaces';
import { logChoiceSelection } from './utils/logging';

const ShoppingCartCalcPage = dynamic(() => import('./ShoppingCartCalcPage'));

type Props = {
  state: InterestStore;
  dispatch: Dispatch<InterestActionTypes>;
  onAcceptCalculation: () => void;
  onUpdateSurfacesSuccess: () => void;
  isPolling: boolean;
};

const CalcPageWrapper = ({
  state,
  onAcceptCalculation,
  onUpdateSurfacesSuccess,
  isPolling,
}: Props) => {
  useEffect(() => {
    logCalculationShown();
  }, []);

  const { interest, areAllProductsFetched } = state;

  const {
    availableFinancingOptions,
    selectedFinancingOption,
    availableShoppingCartPackages,
    selectedShoppingCartPackage,
    surfaceConfigurationList,
    changePackage,
    toggleSurface,
    changeFinancingOption,
    isLoadingPackage,
    isMutatingPackageOptions,
    isPackageUpgraded,
  } = useShoppingCart(interest);

  const isMutatingShoppingCart = isLoadingPackage || isMutatingPackageOptions;

  const { updateSurfaceError, isMutatingSurfaces } = useUpdateSurfaces(
    interest.id,
    surfaceConfigurationList,
    selectedShoppingCartPackage,
    onUpdateSurfacesSuccess,
  );

  const changePvProductName = (productName: Cloud$ProductName) => {
    logChoiceSelection({
      choiceLabel: 'product',
      changedTo: productName,
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'pv_product_name', value: productName });
  };

  const changePvPackageSize = (packageSize: Cloud$PackageSize) => {
    logChoiceSelection({
      choiceLabel: 'package',
      changedTo: packageSize,
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'pv_package_size', value: packageSize });
  };

  const changeBatteryPackageSize = (packageSize: Cloud$PackageSize) => {
    logChoiceSelection({
      choiceLabel: 'package',
      changedTo: packageSize,
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'battery_package_size', value: packageSize });
  };

  const toggleBattery = (withBattery: boolean) => {
    logChoiceSelection({
      choiceLabel: 'battery',
      changedTo: withBattery.toString(),
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'with_battery', value: withBattery });
  };

  const toggleEvCharger = (
    mainHardwareType: Cloud$MainHardwareType,
    withEvCharger: boolean,
  ) => {
    logChoiceSelection({
      mainHardwareType: mainHardwareType,
      choiceLabel: 'evCharger',
      changedTo: withEvCharger.toString(),
      experimentVersion: interest.experiment_version,
    });

    changePackage({ option: 'with_ev_charger', value: withEvCharger });
  };

  const handleChangeFinancingOption = (
    newPurchaseModelCode: Cloud$PurchaseModelCode,
  ) => {
    if (!availableFinancingOptions.includes(newPurchaseModelCode)) {
      throw Error(`Invalid purchase model code ${newPurchaseModelCode}`);
    }

    logChoiceSelection({
      choiceLabel: 'purchase model',
      changedTo: newPurchaseModelCode,
      experimentVersion: interest.experiment_version,
    });

    changeFinancingOption(newPurchaseModelCode);
  };

  const handleMapDisplayPolygonClick = (mapPolygon: Surface$MapPolygon) => {
    const { referenceId } = mapPolygon;

    if (!referenceId) {
      throw new Error('Unable to toggle surface without a referenceId');
    }

    toggleSurface(referenceId);
  };

  const firstFinancingOption =
    interest.active_shopping_cart_package?.price.financing_options[0];
  const isFirstFinancingOptionWithoutPVData =
    firstFinancingOption && !firstFinancingOption.pv_data;

  if (isFirstFinancingOptionWithoutPVData) {
    return (
      <ShoppingCartCalcPage
        interest={interest}
        isLoadingPackage={isLoadingPackage}
        isMutatingPackageOptions={isMutatingPackageOptions}
        availableFinancingOptions={availableFinancingOptions}
        availableShoppingCartPackages={availableShoppingCartPackages}
        selectedFinancingOption={selectedFinancingOption}
        selectedShoppingCartPackage={selectedShoppingCartPackage}
        onAcceptCalculation={onAcceptCalculation}
        onChangeFinancingOption={handleChangeFinancingOption}
        onChangeBatteryPackageSize={changeBatteryPackageSize}
        onToggleEvCharger={toggleEvCharger}
      />
    );
  }

  return (
    <CalcPage
      interest={interest}
      areAllProductsFetched={areAllProductsFetched}
      isUpdating={isPolling || isMutatingSurfaces || isMutatingShoppingCart}
      availableFinancingOptions={availableFinancingOptions}
      availableShoppingCartPackages={availableShoppingCartPackages}
      selectedFinancingOption={selectedFinancingOption}
      selectedShoppingCartPackage={selectedShoppingCartPackage}
      updateSurfaceFailed={updateSurfaceError}
      surfaceConfigurationList={surfaceConfigurationList}
      isPackageUpgraded={isPackageUpgraded}
      onAcceptCalculation={onAcceptCalculation}
      onMapDisplayPolygonClick={handleMapDisplayPolygonClick}
      onChangeFinancingOption={handleChangeFinancingOption}
      onChangePvProductName={changePvProductName}
      onChangePvPackageSize={changePvPackageSize}
      onToggleBattery={toggleBattery}
      onToggleEvCharger={toggleEvCharger}
    />
  );
};

export default CalcPageWrapper;
