  const [showSidebar, setShowSidebar] = useState(false);
  const [sidebarContent, setSidebarContent] = useState<handleSidebarProps>();

  const bodyFontSize = { s: 2, m2: 4 };

  const SECONDS = 1000;
  const calcAcceptDelay = !Number.isNaN(calcAcceptedDialogDelayOverride)
    ? calcAcceptedDialogDelayOverride * SECONDS
    : config.pages.calcPage.calcAcceptedDialogDelay * SECONDS;

  const handleSidebar = (sidebarConentType: handleSidebarProps) => {
    if (!showSidebar) setShowSidebar(true);
    setSidebarContent(sidebarConentType);
