    isEnabled(SHOW_REPRESENTATIVE_EXAMPLES_ON_CALC_PAGE, config) &&
    isLeasingInPurchaseModels;

  const isPhysicalStore = isPhysicalStoreSalesFlow();

  const mainHardwareType = getMainHardwareType(interest);

  return (
    <div>
      <SidebarContext.Provider
        value={{
          openContactMeModal: () => contactMeModalToggled(true, 'Sidebar'),
        }}
      >
        <Sidebar show={showSidebar} onDismiss={() => setShowSidebar(false)}>
