        {isInfoSectionEnabled && <InfoSectionWrapper />}
        <FinancingSection
          selectedFinancingOption={selectedFinancingOption}
          selectedShoppingCartPackage={selectedShoppingCartPackage}
          availableFinancingOptions={availableFinancingOptions}
          setShowContactMeModal={(shown) =>
            contactMeModalToggled(shown, 'Financing Section')
          }
          onChangeFinancingOption={onChangeFinancingOption}
          totalSavings={totalSavings}
          updateTotalSavings={setTotalSavings}
          handleScrollToConfiguration={scrollToConfiguration}
          showEditPackage={multiplePackages}
          onToggleBattery={onToggleBattery}
          showBuyNowDisclaimer={showBuyNowDisclaimer}
          isLeasingInPurchaseModels={isLeasingInPurchaseModels}
          isOtovoCampaignActive={interest.is_otovo_campaign}
        />
        {representativeExampleEnabled && (
          <SectionWrapperTailwind>
            <RepresentativeExampleSection />
