        )}
        <ContactMeModal
          interest={interest}
          isInterestActivated={isInterestActivated}
          onAcceptCalculation={handleAcceptCalculation}
          selectedFinancingOption={selectedFinancingOption}
          selectedShoppingCartPackage={selectedShoppingCartPackage}
          showContactMeModal={showContactMeModal}
          onClose={() => contactMeModalToggled(false, '')}
        />
        <SurfaceSection
          interest={interest}
          onMapDisplayPolygonClick={onMapDisplayPolygonClick}
          selectedShoppingCartPackage={selectedShoppingCartPackage}
          surfaceConfigurationList={surfaceConfigurationList}
          updateFailed={updateSurfaceFailed}
          isUpdating={isUpdating}
        />
        {showSocialProofSection && <SocialProofSection />}
        <SectionWrapperTailwind>
          <WhatsNextSection mainHardwareType={mainHardwareType} />
        </SectionWrapperTailwind>
        <FAQSection />
        <StickyContent
          selectedFinancingOption={selectedFinancingOption}
          isAccepted={isAccepted}
          setShowContactMeModal={(shown) =>
            contactMeModalToggled(shown, 'Sticky Header')
          }
        />
      </SidebarContext.Provider>
    </div>
  );
};

export default CalcPage;
