} from '@otovo/shared/types/cloudApi';
import { isBatteryPackage, isEvChargerPackage } from '../../lib/packageUtils';
import {
  SELECT_PACKAGE,
  SELECT_PURCHASE_MODEL,
  TOGGLE_SURFACE,
  UPDATE_INTEREST,
} from './actionTypes';
import { InterestTransformerStore } from './type';
import getPreferredOptions from './utils/getPreferredOptions';
import getUserSelections from './utils/getUserSelections';
import { Cloud$PurchaseModelCode } from '@otovo/shared/types/cloudEnums';

type TransformerInterestActionTypes =
  | {
      readonly type: typeof SELECT_PACKAGE;
      readonly selectedPackage: Cloud$PackageRequestPV;
    }
  | {
      readonly type: typeof SELECT_PURCHASE_MODEL;
      readonly selectedPurchaseModel: Cloud$PurchaseModelCode;
    }
  | {
      readonly type: typeof TOGGLE_SURFACE;
      readonly referenceId: string;
    }
  | {
      readonly type: typeof UPDATE_INTEREST;
      readonly interest: Cloud$Interest;
    };

export function createInitialInterestTransformerStore(
  interest: Cloud$Interest,
): InterestTransformerStore {
  const preferredOptions = getPreferredOptions(interest);
  const initial = getUserSelections(interest, preferredOptions);

  return {
    interest,
    ...initial,
    previousPackage: initial.selectedPackage,
  };
}

export default function tranformerReducer(
  state: InterestTransformerStore,
  action: TransformerInterestActionTypes,
): InterestTransformerStore {
  switch (action.type) {
    case SELECT_PACKAGE:
      return {
        ...state,
        ...getUserSelections(state.interest, {
          preferredProductName: action.selectedPackage.pv_product_name,
          preferredPackageSlug: action.selectedPackage.pv_package_size,
          preferredPurchaseModelCode:
            state.selectedFinancingOption?.purchase_model_code,
          preferBatteryPackage: action.selectedPackage.with_battery,
          preferEvChargerPackage: action.selectedPackage.with_ev_charger,
        }),
        previousPackage: state.selectedPackage,
      };

    case SELECT_PURCHASE_MODEL:
      return {
        ...state,
        ...getUserSelections(state.interest, {
          preferredProductName: state.selectedProduct?.name,
          preferredPackageId: state.selectedPackage && state.selectedPackage.id,
          preferredPackageSlug:
            state.selectedPackage && state.selectedPackage.package_size,
          preferredPurchaseModelCode: action.selectedPurchaseModel,
          preferBatteryPackage: state.selectedPackage
            ? isBatteryPackage(state.selectedPackage)
            : undefined,
          preferEvChargerPackage: state.selectedPackage
            ? isEvChargerPackage(state.selectedPackage)
            : undefined,
        }),
      };

    case TOGGLE_SURFACE:
      return {
        ...state,
        surfaceConfigurationList: [
          ...state.surfaceConfigurationList.map((surfaceConfiguration) =>
            surfaceConfiguration.surfaceId === action.referenceId
              ? {
                  ...surfaceConfiguration,
                  ...{
                    isSelected: !surfaceConfiguration.isSelected,
                  },
                }
              : surfaceConfiguration,
          ),
        ],
      };

    case UPDATE_INTEREST:
      return {
        ...state,
        interest: action.interest,
        ...getUserSelections(action.interest, {
          preferredProductName: state.selectedPackage?.product_name,
          preferredPackageSlug: state.selectedPackage?.package_size,
          preferredPurchaseModelCode:
            state.selectedFinancingOption?.purchase_model_code,
          preferBatteryPackage: state.selectedPackage
            ? isBatteryPackage(state.selectedPackage)
            : undefined,
          preferEvChargerPackage: state.selectedPackage
            ? isEvChargerPackage(state.selectedPackage)
            : undefined,
        }),
        previousPackage: state.selectedPackage,
      };

    default:
      return action satisfies never;
  }
}
