```ts web/breeze/stores/Interest/utils/filterPackagesByHardware.ts
import { Cloud$Package } from '@otovo/shared/types/cloudApi';

type Args = {
  packages: Array<Cloud$Package>;
  battery?: boolean;
  evCharger?: boolean;
};

function filterPackagesByHardware({
  packages,
  battery = false,
  evCharger = false,
}: Args): Array<Cloud$Package> {
  const primaryResult = packages.filter(
    (pkg: Cloud$Package) =>
      !!battery === !!pkg.price.equipment.batteries.length &&
      !!evCharger === !!pkg.price.equipment.ev_chargers.length,
  );
  if (primaryResult.length) {
    return primaryResult;
  }
  // If we can’t satisfy both the battery and the EV charger requirement, we
  // fall back to satisfying only the battery requirement. This edge case can
  // be relevant when a market starts supporting EV chargers and configures them
  // to be selected by default, but existing interests don’t have any EV charger
  // packages yet.
  const secondaryResult = packages.filter(
    (pkg: Cloud$Package) =>
      !!battery === !!pkg.price.equipment.batteries.length,
  );
  return secondaryResult;
}

export default filterPackagesByHardware;
