Based on the code shared, I'll propose a modern approach using SWR and custom hooks that make the data and actions more accessible while maintaining type safety. Here's how I'd structure it:

```typescript
// hooks/useInterest/types.ts
export type UseInterestConfig = {
  // If true, will poll until calculation is complete
  waitForCalculation?: boolean;
  // Custom polling interval (defaults to 2000ms)
  pollingInterval?: number;
  // Optional callback when calculation completes
  onCalculationComplete?: (interest: Cloud$Interest) => void;
}

export type InterestActions = {
  // Package related actions
  selectPackage: (params: {
    productName: Cloud$ProductName;
    packageSize: Cloud$PackageSize;
    withBattery?: boolean;
    withEvCharger?: boolean;
  }) => Promise<void>;

  // Financing related actions
  selectFinancingOption: (code: Cloud$PurchaseModelCode) => Promise<void>;

  // Surface related actions
  toggleSurface: (surfaceId: string) => Promise<void>;

  // Misc actions
  refetchCalculation: () => Promise<void>;
}

export type UseInterestReturn = {
  // Data
  interest: Cloud$Interest | undefined;
  selectedPackage: Cloud$Package | undefined;
  selectedFinancingOption: Cloud$FinancingOption | undefined;
  availableFinancingOptions: Cloud$PurchaseModelCode[];
  surfaceConfiguration: SurfaceConfiguration[];

  // State
  isLoading: boolean;
  isPolling: boolean;
  isCalculating: boolean;
  error: Error | undefined;

  // Actions
  actions: InterestActions;
}
