```typescript
// hooks/useInterest/index.ts
import useSWR, { mutate } from 'swr';
import { UseInterestConfig, UseInterestReturn } from './types';

const INTEREST_CACHE_KEY = (id: string) => `/api/interests/${id}`;

export function useInterest(
  interestId: string,
  config?: UseInterestConfig
): UseInterestReturn {
  const {
    waitForCalculation = false,
    pollingInterval = 2000,
    onCalculationComplete,
  } = config ?? {};

  // Main interest data fetching
  const { data: interest, error, isLoading } = useSWR<Cloud$Interest>(
    INTEREST_CACHE_KEY(interestId),
    fetchInterest, // Your existing fetch function
    {
      // Only poll if waiting for calculation and not yet complete
      refreshInterval: waitForCalculation && !interest?.calc_created_at 
        ? pollingInterval 
        : 0,
      onSuccess: (data) => {
        if (data.calc_created_at && onCalculationComplete) {
          onCalculationComplete(data);
        }
      },
    }
  );

  // Derived state
  const isPolling = waitForCalculation && !interest?.calc_created_at;
  const isCalculating = !interest?.calc_created_at;

  // Selected package & financing options
  const selectedPackage = useMemo(
    () => interest?.active_shopping_cart_package,
    [interest]
  );

  const selectedFinancingOption = useMemo(
    () => selectedPackage?.price.financing_options.find(
      (option) => option.purchase_model_code === interest?.default_purchase_model
    ),
    [selectedPackage, interest]
  );

  const availableFinancingOptions = useMemo(
    () => selectedPackage?.price.financing_options.map(
      (option) => option.purchase_model_code
    ) ?? [],
    [selectedPackage]
  );

  // Surface configuration
  const surfaceConfiguration = useMemo(
    () => interest && selectedPackage 
      ? getSurfaceConfigurationList(interest, selectedPackage)
      : [],
    [interest, selectedPackage]
  );

  // Actions
  const actions: InterestActions = {
    async selectPackage({ productName, packageSize, withBattery, withEvCharger }) {
      const response = await updateInterestPackage(interestId, {
        product_name: productName,
        package_size: packageSize,
        with_battery: withBattery,
        with_ev_charger: withEvCharger,
      });
      await mutate(INTEREST_CACHE_KEY(interestId));
      return response;
    },

    async selectFinancingOption(purchaseModelCode) {
      const response = await updateInterestFinancing(interestId, purchaseModelCode);
      await mutate(INTEREST_CACHE_KEY(interestId));
      return response;
    },

    async toggleSurface(surfaceId) {
      const response = await updateInterestSurfaces(interestId, surfaceId);
      await mutate(INTEREST_CACHE_KEY(interestId));
      return response;
    },

    async refetchCalculation() {
      await mutate(INTEREST_CACHE_KEY(interestId));
    },
  };

  return {
    // Data
    interest,
    selectedPackage,
    selectedFinancingOption,
    availableFinancingOptions,
    surfaceConfiguration,

    // State
    isLoading,
    isPolling,
    isCalculating,
    error,

    // Actions
    actions,
  };
}
